import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String input = scanner.nextLine();

        int maxLength = 10; // Maximum length for buffer
        char[] buffer = new char[maxLength];

        if (input.length() > maxLength) {
            System.out.println("Input string exceeds buffer size. Truncating to " + maxLength + " characters.");
            input = input.substring(0, maxLength); // Truncate input if it exceeds buffer size
        }

        input.getChars(0, input.length(), buffer, 0);

        System.out.println("Buffer contents: " + String.valueOf(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
